// Parse the 2D 'values' array from the Graph usedRange into per-location pricing
// records, then build a Firestore PATCH body for pricing/current.
// Sheet layout (tab 'New Price Sheet 2026'): header on sheet row 4, data from row 5.
// Columns A..Y map to KEYS below. Stop at the 'INACTIVE LOCATION' divider; skip the
// repeated 'STATE' header row; a row with pricing but no state/city/address is a
// continuation of the previous location (fills its blanks) — e.g. Walnut.

const resp = $input.first().json || {};
const values = Array.isArray(resp.values) ? resp.values : [];
const KEYS = [null,'state','city','address','sub2k','r2_5k','r5k','r5k_12mo','office_mo','office','dock','desk','virtual','truck','small_veh','wifi','annual','deposit','dp_office','dp_wh','dp_xdock','studio','conf','event','amenities','special'];

function clean(v){
  if(v === null || v === undefined || v === '') return '';
  if(typeof v === 'number') return Number.isInteger(v) ? v : Math.round(v*10000)/10000;
  return String(v).trim();
}

const rows = [];
for(let i = 4; i < values.length; i++){          // i=4 -> sheet row 5
  const row = values[i] || [];
  const a = clean(row[0]);
  if(a === 'INACTIVE LOCATION') break;
  if(a === 'STATE') continue;                     // repeated header
  const cells = [];
  for(let c = 0; c < 25; c++) cells.push(clean(row[c]));
  if(!cells.some(x => x !== '')) continue;         // blank row
  const rec = {};
  for(let c = 0; c < 25; c++){ const k = KEYS[c+1]; if(cells[c] !== '') rec[k] = cells[c]; }
  const hasLoc = rec.state || rec.city || rec.address;
  if(!hasLoc && rows.length){                       // continuation -> fill prior
    const prev = rows[rows.length-1];
    for(const k in rec){ if(prev[k] === undefined) prev[k] = rec[k]; }
    continue;
  }
  rows.push(rec);
}
rows.forEach((r, idx) => { r._id = 'p' + idx; });

function fv(v){
  if(typeof v === 'number') return Number.isInteger(v) ? { integerValue: String(v) } : { doubleValue: v };
  return { stringValue: String(v) };
}
const arr = rows.map(r => { const fields = {}; for(const k in r) fields[k] = fv(r[k]); return { mapValue: { fields } }; });
const patchBody = { fields: {
  rows:      { arrayValue: { values: arr } },
  updatedAt: { stringValue: new Date().toISOString() },
  source:    { stringValue: 'n8n pricing sync' },
  count:     { integerValue: String(rows.length) }
}};

if(rows.length === 0) throw new Error('Pricing parse produced 0 rows — check the worksheet name/usedRange.');
return [{ json: { patchBody, count: rows.length } }];
